sed -i 's/const vendasHoje=DB.vendas.filter(v=>(v.data||"").slice(0,10)===currentCaixaDate);/const normDt=(d)=>{if(!d)return"";d=String(d).split("T")[0];if(d.includes("\/")){const p=d.split("\/");if(p.length===3)return p[2]+"-"+p[1].padStart(2,"0")+"-"+p[0].padStart(2,"0");}return d.slice(0,10);};const cDate=normDt(currentCaixaDate);const vendasHoje=DB.vendas.filter(v=>normDt(v.data)===cDate);/g' js/app.js
